INSERT INTO services (id, category_id, slug, title, description, duration, price, is_active, badge, benefits) VALUES
('55555555-5555-0000-0000-000000000001', '44444444-4444-0000-0000-000000000001', 'masage-spine', 'Масаж спини та шиї', 'Глибоке опрацювання м''язів спини та шийно-комірцевої зони.', 45, 1500.00, TRUE, 'Popular', ARRAY['Знімає напругу та біль', 'Покращує поставу', 'Позбавляє від головного болю']),
('55555555-5555-0000-0000-000000000002', '44444444-4444-0000-0000-000000000001', 'sportive-masage', 'Спортивний масаж (все тіло)', 'Інтенсивний масаж для відновлення м''язів.', 90, 3000.00, TRUE, NULL, ARRAY['Швидке відновлення м''язів', 'Підвищує витривалість', 'Виводить молочну кислоту']),
('55555555-5555-0000-0000-000000000003', '44444444-4444-0000-0000-000000000002', 'aromatherapy', 'Ароматерапія', 'Розслабляючий масаж з використанням ефірних олій.', 60, 2000.00, TRUE, 'Recommended', ARRAY['Глибока релаксація', 'Покращення сну', 'Органічні ефірні олії']),
('55555555-5555-0000-0000-000000000004', '44444444-4444-0000-0000-000000000002', 'stone-massage', 'Масаж гарячими каменями', 'Стоун-терапія для глибокого релаксу.', 90, 3500.00, TRUE, NULL, ARRAY['Зняття стресу', 'Глибоке прогрівання тканин', 'Детоксикація організму']),
('55555555-5555-0000-0000-000000000005', '44444444-4444-0000-0000-000000000002', 'honey-massage', 'Медовий масаж', 'Антицелюлітний та детокс-ефект за допомогою натурального меду.', 60, 2500.00, TRUE, 'New', ARRAY['Антицелюлітна дія', 'Живлення шкіри', 'Прискорює кровообіг']),
('55555555-5555-0000-0000-000000000006', '44444444-4444-0000-0000-000000000003', 'facial-classic', 'Класичний масаж обличчя', 'Ліфтинг та розслаблення м''язів обличчя.', 30, 1200.00, TRUE, NULL, ARRAY['Ефект ліфтингу', 'Здоровий колір обличчя', 'Зменшує набряки']),
('55555555-5555-0000-0000-000000000007', '44444444-4444-0000-0000-000000000004', 'massage-therapeutic', 'Загальнозміцнюючий лікувальний', 'Медичний масаж для поліпшення загального стану організму.', 60, 1800.00, TRUE, NULL, ARRAY['Покращує кровообіг', 'Зміцнює імунітет', 'Усуває застійні явища']),
('55555555-5555-0000-0000-000000000008', '44444444-4444-0000-0000-000000000005', 'massage-thai', 'Тайський традиційний', 'Стародавній метод пасивного розтягування та точкового масажу.', 90, 2500.00, TRUE, NULL, ARRAY['Збільшує гнучкість', 'Відновлює енергію', 'Глибоке розслаблення']),
('55555555-5555-0000-0000-000000000009', '44444444-4444-0000-0000-000000000006', 'massage-pregnancy', 'Масаж для майбутніх мам', 'Бережний масаж для зняття навантаження зі спини та ніг.', 60, 1600.00, TRUE, NULL, ARRAY['Зменшує набряки', 'Покращує емоційний стан', 'Безпечно для малюка']),
('55555555-5555-0000-0000-000000000010', '44444444-4444-0000-0000-000000000007', 'massage-anti-cellulite', 'Антицелюлітний (ручний)', 'Ефективна техніка для корекції фігури та покращення шкіри.', 45, 1400.00, TRUE, NULL, ARRAY['Корекція фігури', 'Покращення лімфодренажу', 'Гладка шкіра']),
('55555555-5555-0000-0000-000000000011', '44444444-4444-0000-0000-000000000008', 'massage-kids', 'Дитячий масаж (до 12 років)', 'Спеціальний масаж для підтримки здорового розвитку дитини.', 30, 900.00, TRUE, NULL, ARRAY['Правильне формування постави', 'Зміцнення м''язів', 'Заспокійливий ефект']);
